
-- Script compatible con MySQL Workbench / MySQL 8.x
-- Fuente: Inventario DTIC 2026.xlsx
-- Ajustes de compatibilidad aplicados:
-- 1) Se eliminaron restricciones UNIQUE riesgosas sobre nombres de custodios/ubicaciones.
-- 2) Todas las fechas fueron normalizadas al formato YYYY-MM-DD.
-- 3) Los costos fueron normalizados a formato numérico compatible con DECIMAL.
-- 4) Los códigos SBAI/SBYE duplicados, vacíos o 'S/N' se resolvieron con una PK técnica en codigo_sbai.
--    El valor original se conserva en codigo_sbai_original.
-- 5) La tabla modems usa numero_servicio como clave primaria.

DROP DATABASE IF EXISTS inventario_dtic_2026;
CREATE DATABASE inventario_dtic_2026
  CHARACTER SET utf8mb4
  COLLATE utf8mb4_unicode_ci;
USE inventario_dtic_2026;

SET NAMES utf8mb4;
SET FOREIGN_KEY_CHECKS = 0;

CREATE TABLE custodios (
    id_custodio INT NOT NULL PRIMARY KEY,
    nombre VARCHAR(255) NOT NULL,
    KEY idx_custodios_nombre (nombre)
) ENGINE=InnoDB;

CREATE TABLE ubicaciones (
    id_ubicacion INT NOT NULL PRIMARY KEY,
    clave_ubicacion VARCHAR(255) NULL,
    edificio VARCHAR(120) NULL,
    piso VARCHAR(60) NULL,
    detalle VARCHAR(150) NULL,
    KEY idx_ubicaciones_clave (clave_ubicacion)
) ENGINE=InnoDB;

CREATE TABLE pcs (
    codigo_sbai VARCHAR(120) NOT NULL PRIMARY KEY,
    codigo_sbai_original VARCHAR(120) NULL,
    codigo_megan VARCHAR(120) NULL,
    descripcion VARCHAR(255) NULL,
    fecha_ingreso DATE NULL,
    costo DECIMAL(12,2) NULL,
    marca VARCHAR(120) NULL,
    modelo VARCHAR(200) NULL,
    sn VARCHAR(150) NULL,
    id_custodio_actual INT NULL,
    id_ubicacion INT NULL,
    ultima_actualizacion DATE NULL,
    procesador VARCHAR(150) NULL,
    ram VARCHAR(100) NULL,
    disco_duro VARCHAR(100) NULL,
    so VARCHAR(100) NULL,
    estado VARCHAR(100) NULL,
    observacion TEXT NULL,
    ultimo_mantenimiento DATE NULL,
    fila_excel INT NOT NULL,
    KEY idx_pcs_custodio_actual (id_custodio_actual),
    KEY idx_pcs_ubicacion (id_ubicacion),
    CONSTRAINT fk_pcs_custodio_actual FOREIGN KEY (id_custodio_actual) REFERENCES custodios(id_custodio),
    CONSTRAINT fk_pcs_ubicacion FOREIGN KEY (id_ubicacion) REFERENCES ubicaciones(id_ubicacion)
) ENGINE=InnoDB;

CREATE TABLE perifericos (
    codigo_sbai VARCHAR(120) NOT NULL PRIMARY KEY,
    codigo_sbai_original VARCHAR(120) NULL,
    codigo_megan VARCHAR(120) NULL,
    descripcion VARCHAR(255) NULL,
    marca VARCHAR(120) NULL,
    modelo VARCHAR(200) NULL,
    sn VARCHAR(150) NULL,
    id_custodio_actual INT NULL,
    id_ubicacion INT NULL,
    ultima_actualizacion DATE NULL,
    caracteristicas TEXT NULL,
    estado VARCHAR(100) NULL,
    observacion TEXT NULL,
    fila_excel INT NOT NULL,
    KEY idx_perifericos_custodio_actual (id_custodio_actual),
    KEY idx_perifericos_ubicacion (id_ubicacion),
    CONSTRAINT fk_perifericos_custodio_actual FOREIGN KEY (id_custodio_actual) REFERENCES custodios(id_custodio),
    CONSTRAINT fk_perifericos_ubicacion FOREIGN KEY (id_ubicacion) REFERENCES ubicaciones(id_ubicacion)
) ENGINE=InnoDB;

CREATE TABLE bienes_control_administrativo (
    codigo_sbai VARCHAR(120) NOT NULL PRIMARY KEY,
    codigo_sbai_original VARCHAR(120) NULL,
    codigo_anterior VARCHAR(120) NULL,
    descripcion VARCHAR(255) NULL,
    fecha_ingreso DATE NULL,
    costo DECIMAL(12,2) NULL,
    id_custodio_actual INT NULL,
    id_ubicacion INT NULL,
    ultima_actualizacion DATE NULL,
    estado VARCHAR(100) NULL,
    observacion TEXT NULL,
    fila_excel INT NOT NULL,
    KEY idx_bca_custodio_actual (id_custodio_actual),
    KEY idx_bca_ubicacion (id_ubicacion),
    CONSTRAINT fk_bca_custodio_actual FOREIGN KEY (id_custodio_actual) REFERENCES custodios(id_custodio),
    CONSTRAINT fk_bca_ubicacion FOREIGN KEY (id_ubicacion) REFERENCES ubicaciones(id_ubicacion)
) ENGINE=InnoDB;

