-- Resumen de carga
SELECT 'custodios' AS tabla, COUNT(*) AS registros FROM custodios
UNION ALL SELECT 'ubicaciones', COUNT(*) FROM ubicaciones
UNION ALL SELECT 'pcs', COUNT(*) FROM pcs
UNION ALL SELECT 'perifericos', COUNT(*) FROM perifericos
UNION ALL SELECT 'bienes_control_administrativo', COUNT(*) FROM bienes_control_administrativo
